//intelligence-utils.js

import { SANKEY_CHARTNAME as SANKEY } from "../core/chartname-constants";
import { DATALABELS_LABELTYPE as DATALABELS } from "../label/labeltype-constants";
import { invokeFunction } from "./zcutils";

export function dimension_based_intelligence(chartObj, factor, dimension) {
    var intelligenceInfo = +chartObj.systemConf.canvas.intelligence.dimension[factor];
    return dimension >= intelligenceInfo;
}

export function datacount_based_intelligence(chartObj, factor) {
    var intelligenceInfo = +chartObj.systemConf.canvas.intelligence.dataCount[factor];
    intelligenceInfo = invokeFunction(intelligenceInfo, chartObj);
    const dataObject = chartObj.dataObject;
    let criteria = (factor == DATALABELS && chartObj.distinctChartTypes[0] == SANKEY) ? intelligenceInfo >= dataObject.sankeyLayout.completeGraph.nodes.length
        : intelligenceInfo >= dataObject.totalnoofdatas;
    return criteria;
}
